# Simple Counter App

<!-- FULL_CODE_START
// MainWindow.xaml
<StackPanel VerticalAlignment="Center" HorizontalAlignment="Center">
    <TextBlock x:Name="CounterText" Text="0" FontSize="40" HorizontalAlignment="Center"/>
    <Button Content="Increment" Click="Increment_Click" Margin="0,20,0,0" Padding="10"/>
</StackPanel>

// MainWindow.xaml.cs
using System.Windows;

namespace CounterApp {
    public partial class MainWindow : Window {
        private int count = 0;

        public MainWindow() {
            InitializeComponent();
        }

        private void Increment_Click(object sender, RoutedEventArgs e) {
            count++;
            CounterText.Text = count.ToString();
        }
    }
}
FULL_CODE_END -->
